import re

class Stack:
    def __init__(self):
        self.items = []

    def push(self, item):
        self.items.append(item)

    def pop(self):
        if not self.is_empty():
            return self.items.pop()
        return None

    def peek(self):
        if not self.is_empty():
            return self.items[-1]
        return None

    def is_empty(self):
        return len(self.items) == 0

def tokenize_expression(expression):
    token_pattern = re.compile(r'\d+(?:\.\d*)?|[+\-*/%^()]')
    return token_pattern.findall(expression)

def infix_to_postfix(infix_expr):
    precedence = {
        '+': 1, '-': 1,
        '*': 2, '/': 2, '%': 2,
        '^': 3
    }
    right_associative = {'^'}

    output = []
    operator_stack = Stack()

    tokens = tokenize_expression(infix_expr)

    for token in tokens:
        if token.isalnum() or (token.replace('.', '', 1).isdigit() and token.count('.') <= 1):
            output.append(token)
        elif token == '(':
            operator_stack.push(token)
        elif token == ')':
            while not operator_stack.is_empty() and operator_stack.peek() != '(':
                output.append(operator_stack.pop())
            if not operator_stack.is_empty() and operator_stack.peek() == '(':
                operator_stack.pop()
        elif token in precedence:
            while (not operator_stack.is_empty() and
                   operator_stack.peek() != '(' and
                   (precedence.get(token, 0) < precedence.get(operator_stack.peek(), 0) or
                    (precedence.get(token, 0) == precedence.get(operator_stack.peek(), 0) and
                     token not in right_associative))):
                output.append(operator_stack.pop())
            operator_stack.push(token)

    while not operator_stack.is_empty():
        output.append(operator_stack.pop())

    return ' '.join(output)
